/**
 * deduplicate-openapi-methods.mjs
 *
 * Change Tracker Hub's OpenAPI spec (auto-generated by ASP.NET Swashbuckle)
 * exposes both GET and POST on virtually every endpoint. This script removes
 * the method that doesn't match REST semantics for each endpoint, cutting the
 * generated API reference roughly in half.
 *
 * Conservative rules — when in doubt, keep both:
 *   1. Operation summary is the primary signal (wins over path heuristics).
 *   2. Path-segment keywords are a fallback when the summary is ambiguous/empty.
 *   3. A fixed set of genuinely dual-method endpoints always keep both.
 *
 * Idempotent: if no duplicate methods are found, the YAML file is not rewritten.
 *
 * Usage:
 *   node scripts/deduplicate-openapi-methods.mjs
 */

import { readFileSync, writeFileSync } from 'fs';
import { load, dump } from 'js-yaml';
import { fileURLToPath } from 'url';
import path from 'path';

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const YAML_PATH = path.join(ROOT, 'static', 'openapi', 'changetracker-hub-8.1.yaml');

// ── Endpoints where GET and POST do genuinely different things ──────────────
const KEEP_BOTH = new Set([
  '/commandParser/whitelist',                  // GET=retrieve list, POST=add to list
  '/commandParser/commandComponent/templates', // GET=retrieve, POST=set
  '/auth/{provider}',                          // GET=OAuth redirect, POST=credential auth
  '/auth',
  '/access-token',                             // empty summary — intent unclear
  '/cloudTemplate/status',                     // ambiguous "Provides/Gets" summary
  '/policyTemplate/setup',                     // "Ensures" — could be read or write
  '/reportExecute',                            // vague "Report Service" summary
  '/reportRender',
  '/reportRenderStart',
  // Downloads: some clients POST to carry auth/filter in a body
  '/downloadAgentUpdate/{VersionRequested}',
  '/downloadAgentUpdate/{VersionRequested}/{UpdateType}',
  '/downloadFileHash/{HostType}/{OperatingSystem}/{Variant}',
  '/downloadFileHashById/{FileId}',
  '/plannedChanges/download',
  // Empty summary, no clear path signal
  '/reports/ruleresults',
  '/stats/compliancesummarydata',
]);

// ── Summary prefixes that unambiguously mean "mutation → keep POST" ─────────
const MUTATION_SUMMARY = [
  'add ', 'adds ', 'update ', 'updates ',
  'delete ', 'deletes ', 'remove ', 'removes ',
  'register ', 'registers ', 'submit ', 'submits ',
  'upload ', 'uploads ', 'reset ', 'resets ',
  'save ', 'saves ', 'clone ', 'clones ',
  'create ', 'creates ', 'send ', 'sends ',
  'set ', 'sets ', 'store ', 'stores ',
  'mark ', 'marks ',
  'acknowledge ', 'acknowledges ',
  'invalidate ', 'invalidates ',
  'test ', 'tests ',       // test*Connection endpoints trigger external calls
  'attempt ', 'attempts ',
  'used to submit', 'used to add',
  'discover ', 'discovers ',
  'export ', 'exports ',
  're-parents', 'resubmit',
  'ask an agent',          // sends a command to a remote agent
  'validates ',            // validates a password — sends credentials
];

// ── Summary prefixes that unambiguously mean "read → keep GET" ───────────────
const READ_SUMMARY = [
  'get ', 'gets ', 'retrieve ', 'retrieves ',
  'return ', 'returns ',
  'list ', 'lists ',
  'fetch ', 'fetches ',
  'requests information',
  'a request to return',
  'a request to get',
  'a request to find',
  'has the current user',
  'echos ', 'echo ',
  'checks whether',
  'called by the agent, this returns',
  'report service',        // all vague "Report Service" entries are list/get operations
  'stats service',
  'represents a request to get',
  'sign in',
];

// ── Path-segment prefixes used as fallback when summary is ambiguous ─────────
// Intentionally narrow: compound words like addOrUpdate, deleteRule, reevaluateEvents
// all start with a keyword, so startsWith() catches them without regex complexity.
// "start" and "sync" are excluded — too many false positives as path-parameter separators.
const MUTATION_SEGMENTS = [
  'add', 'update', 'delete', 'register', 'submit',
  'upload', 'save', 'clone', 'create', 'reset',
  'promote', 'reparent', 'reregister',
  'apply', 'export', 'discover', 'resubmit',
  'acknowledge', 'setcomment', 'invalidate', 'ignore',
  'reevaluate', 'start',
];

function startsWith(str, prefixes) {
  return prefixes.some(p => str.startsWith(p));
}

function classify(apiPath, methods) {
  if (KEEP_BOTH.has(apiPath)) return 'both';

  const summary = ((methods.get || {}).summary || '').trim().toLowerCase();
  const segments = apiPath.split('/').filter(s => s && !s.startsWith('{'));

  if (startsWith(summary, MUTATION_SUMMARY)) return 'post';
  if (startsWith(summary, READ_SUMMARY))     return 'get';

  const isMutationPath = segments.some(seg =>
    MUTATION_SEGMENTS.some(pfx => seg.toLowerCase().startsWith(pfx))
  );
  if (isMutationPath) return 'post';

  return 'both';
}

// ── Main ─────────────────────────────────────────────────────────────────────

const text = readFileSync(YAML_PATH, 'utf8');
const spec = load(text);

let removedGet = 0;
let removedPost = 0;

for (const [apiPath, methods] of Object.entries(spec.paths || {})) {
  if (!('get' in methods) || !('post' in methods)) continue;

  const decision = classify(apiPath, methods);
  if (decision === 'post') {
    delete spec.paths[apiPath].get;
    removedGet++;
  } else if (decision === 'get') {
    delete spec.paths[apiPath].post;
    removedPost++;
  }
}

if (removedGet === 0 && removedPost === 0) {
  console.log('deduplicate-openapi-methods: no duplicate methods found, spec is already clean.');
  process.exit(0);
}

writeFileSync(
  YAML_PATH,
  dump(spec, { noRefs: true, lineWidth: -1, sortKeys: false }),
  'utf8'
);

console.log(
  `deduplicate-openapi-methods: removed ${removedGet} GET and ${removedPost} POST operations` +
  ` from ${YAML_PATH}`
);
